using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;

struct _
{
	int l, r, w;
};
bool cmp(const _ &a, const _ &b)
{
	return a.w < b.w;
}
vector<_> g;
vector<_> dusss;
int fa[123322], n, m, k, _ns, c__, a[20][11000];
int qwq = 0x3f3f3f3f3f3f3f3f;
bool awa[123456];
int find(int x)
{
	if (fa[x] == x)
	{
		return x;
	}
	else
	{
		return fa[x] = find(fa[x]);
	}
}
signed main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);

	cin >> n >> m >> k;
	for (int i = 1; i <= n; ++i)
	{
		fa[i] = i;
	}
	for (int i = 1, u, v, w; i <= m; ++i)
	{
		v=read(),u=read(),w=read();
		g.push_back({v, u, w});
	}
	for (int i = 1; i <= k; ++i)
	{
		cin >> a[i][0];
		for (int j = 1; j <= n; ++j)
		{
			a[i][j]=read();
			g.push_back({i + n, j, a[i][j]});
		}
	}
	sort(g.begin(), g.end(), cmp);
	for (int cs = 0; cs < (1 << k); ++cs)
	{
		for (int i = 1; i <= n + k; ++i)
		{
			fa[i] = i;
			awa[i] = false;
		}
		int noi = 0, ccfnoi = n;
		for (int ccf = 1; ccf <= k; ++ccf)
		{
			if (cs >> (ccf - 1) & 1)
			{
				ccfnoi++;
				noi += a[ccf][0];
				awa[ccf+n] = 1;
			}
		}
		c__ = 0;
		for (int i = 0; i < g.size(); ++i)
		{
			int fx = find(g[i].l), fy = find(g[i].r);
			if (g[i].l > n && awa[g[i].l] == 0)continue;
			if (g[i].r > n && awa[g[i].r] == 0)continue;
			if (fx == fy)
			{
				continue;
			}
			fa[fx] = fy;
			noi += g[i].w;
			c__++;
			if (c__ == ccfnoi - 1)
			{
				break;
			}
		}
		qwq = min(qwq, noi);
	}
	cout << qwq;


	return false;
}
